module top_module(
    MUX_X ,
    A0,
    A1,
    S
);output MUX_X ;
    input  A0;
    input  A1;
    input  S ;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    // Implementation of 2:1 multiplexer
    assign MUX_X = (S == 0) ? A0 : A1;

endmodule
